import{_ as e,o as t,c as o,ae as r}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Update in Cohort Analytics","description":"","frontmatter":{"title":"Update in Cohort Analytics","slug":"update-in-cohort-analytics"},"headers":[],"relativePath":"account-hub/update-in-cohort-analytics.md","filePath":"account-hub/update-in-cohort-analytics.md"}'),n={name:"account-hub/update-in-cohort-analytics.md"};function i(s,a,l,c,d,u){return t(),o("div",null,[...a[0]||(a[0]=[r('<p>Cohort analysis is a powerful tool that helps you understand the full ROI of your campaigns but also helps you guide future investment decisions and consumer targeting. We&#39;ve made awesome improvements in Cohort Analytics 📈</p><h3 id="performance" tabindex="-1">Performance <a class="header-anchor" href="#performance" aria-label="Permalink to &quot;Performance&quot;">​</a></h3><p>Cohorts Analytics has been updated with improved speed and reliability. Through several back-end updates, Branch optimized the architecture for organizing data, leading to better performance on the Dashboard for your reports.</p><h3 id="data-source-calculation" tabindex="-1">Data Source &amp; Calculation <a class="header-anchor" href="#data-source-calculation" aria-label="Permalink to &quot;Data Source &amp; Calculation&quot;">​</a></h3><p>For Re-engagement Cohort, the underlying data source has been changed to provide a more accurate count of users included in the report.</p><p>Additionally, ROAS (return on ad spend) calculations have been improved to report more accurate values for Weekly and Monthly levels. Daily, Weekly, and Monthly values are now calculated individually.</p><h3 id="ui-update" tabindex="-1">UI Update <a class="header-anchor" href="#ui-update" aria-label="Permalink to &quot;UI Update&quot;">​</a></h3><p>The user interface has also been updated! Along with some minor visual artifact fixes, the updated Cohort Analytics aligns with our modern standard.</p><h4 id="sample-screenshot" tabindex="-1">Sample Screenshot <a class="header-anchor" href="#sample-screenshot" aria-label="Permalink to &quot;Sample Screenshot&quot;">​</a></h4><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Ready to get new cohort reports? Visit our guide on Cohort Analytics here: <a href="./cohort-analytics.html">Cohort Analytics</a></p></div>',10)])])}const m=e(n,[["render",i]]);export{p as __pageData,m as default};
